const raw = $input.first().json ?? {};
const body = raw.body ?? raw;
const normalize = (v) => String(v ?? '').trim();

const accessToken = normalize(body.access_token);
const pageId = normalize(body.page_id);
const videoUrl = normalize(body.video_url);
const videoBase64 = normalize(body.videoBase64);
const title = normalize(body.title || 'Reel publicitario');
const description = normalize(body.description || body.post_text || body.caption || '');

if (!accessToken) throw new Error('Se requiere access_token');
if (!pageId) throw new Error('Se requiere page_id');
if (!videoUrl && !videoBase64) throw new Error('Se requiere video_url o videoBase64');

return [{ json: { accessToken, pageId, videoUrl, videoBase64, title, description, hasVideoUrl: !!videoUrl, hasVideoBase64: !!videoBase64 } }];

const response = $input.first().json;
const parsedData = $('Parsear Request').first().json;
const videoId = String(response.video_id || '').trim();
const uploadUrl = String(response.upload_url || '').trim();
if (!videoId || !uploadUrl) throw new Error('Facebook no devolvio video_id o upload_url: ' + JSON.stringify(response));

let videoBuffer;
if (parsedData.hasVideoUrl && parsedData.videoUrl) {
  const resp = await fetch(parsedData.videoUrl);
  if (!resp.ok) throw new Error('No se pudo descargar video desde URL: ' + resp.status);
  const arrayBuf = await resp.arrayBuffer();
  videoBuffer = Buffer.from(arrayBuf);
} else if (parsedData.hasVideoBase64 && parsedData.videoBase64) {
  const clean = parsedData.videoBase64.replace(/^data:video\/\w+;base64,/, '');
  videoBuffer = Buffer.from(clean, 'base64');
} else {
  throw new Error('No hay video para subir');
}

return {
  json: {
    videoId,
    uploadUrl,
    accessToken: parsedData.accessToken,
    pageId: parsedData.pageId,
    title: parsedData.title,
    description: parsedData.description,
    fileSize: videoBuffer.length,
  },
  binary: {
    video: {
      data: videoBuffer,
      mimeType: 'video/mp4',
      fileName: 'reel.mp4',
    }
  }
};

const response = $input.first().json;
const videoData = $('Preparar Video Binario').first().json;
return [{ json: {
  status: response.success ? 'success' : 'error',
  post_id: response.post_id || null,
  video_id: videoData.videoId,
  page_id: videoData.pageId,
  title: videoData.title,
  description: videoData.description,
  file_size_bytes: videoData.fileSize,
  published_at: new Date().toISOString(),
  facebook_response: response,
} }];
